// Alle Items aus dem vorherigen Node holen
const all = $input.all();

const now = new Date();
const since = new Date(now.getTime() - 12 * 60 * 60 * 1000);

const results = [];

// HTML escapen (Telegram mag nur sauberes HTML)
function esc(str = "") {
  return str
    .toString()
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}
for (const item of all) {
  const i = item.json || {};
  const rawDate = i.pubDate || i.isoDate || i.date;
  if (!rawDate) continue;

  const d = new Date(rawDate);
  if (isNaN(d)) continue;
  if (d < since) continue;

  let source = i.author;
  if (!source && i.link) {
    try {
      const url = new URL(i.link);
      source = url.hostname.replace("www.", "");
    } catch {}
  }

  results.push({
    title: esc(i.title || "(no title)"),
    link: i.link || "#",
    dateObj: d,
    when: esc(
      d.toLocaleString("de-DE", {
        day: "2-digit",
        month: "2-digit",
        year: "numeric",
        hour: "2-digit",
        minute: "2-digit",
      })
    ),
    source: esc(source || "unbekannt"),
  });
}

// NEUSTE zuerst (echtes Date-Sort)
results.sort((a, b) => b.dateObj - a.dateObj);

// Text als HTML für Telegram
let text = "*WoW Head News – letzte 12h*\n\n";

if (results.length === 0) {
  text += "Keine neuen Artikel in den letzten 12 Stunden.";
} else {
  text += results
    .map((r) => {
      return `
${r.link}
`.trim();
    })
    .join("\n");
}

return [
  {
    json: {
      telegramText: text,
      count: results.length,
    },
  },
];
